import kotlinx.coroutines.*
import kotlinx.coroutines.test.*
import org.junit.Test
import java.util.concurrent.*
import kotlin.test.*

class NestedException : RuntimeException {
    constructor(message: String) : super(message)
    constructor(cause: Throwable) : super(cause)
    constructor() : super()
}

class ReproducerTest {
    @Test
    fun testNestedException() = runTest {
        val result = runCatching {
            coroutineScope<Unit> {
                throw NestedException(IllegalStateException("ERROR"))
            }
        }
        val ex = result.exceptionOrNull() ?: error("Expected to fail")

        println("Exception class: ${ex.javaClass.name}")
        println("Exception message: ${ex.message}")
        println("Exception cause: ${ex.cause}")
        if (ex.cause != null) {
             println("Exception cause class: ${ex.cause!!.javaClass.name}")
             println("Exception cause message: ${ex.cause!!.message}")
             println("Exception cause cause: ${ex.cause!!.cause}")
        }

        assertTrue(ex is NestedException, "Exception should be NestedException")
        assertTrue(ex.cause is IllegalStateException, "Cause should be IllegalStateException, but was ${ex.cause?.javaClass?.name}")
        assertEquals("ERROR", (ex.cause as IllegalStateException).message)
    }
}
"}

